from functools import lru_cache
from itertools import count
from sympy import prime, integer_log, primorial
from oeis_sequences.OEISsequences import bisection
def A376690(n):
    @lru_cache(maxsize=None)
    def g(x, m): return sum(g(x//(prime(m)**i), m-1) for i in range(1,integer_log(x, prime(m))[0]+1)) if m-1 else x.bit_length()-1
    def f(x):
        c = n-1+x
        for k in count(1):
            if primorial(k)>x:
                break
            c -= g(x,k)
        return c
    return -(m:=bisection(f,n,n))+bisection(lambda x:f(x)+1,m,m) # _Chai Wah Wu_, Mar 18 2026

